parameters.jsonBody:
={{ JSON.stringify({
  contents: [{ parts: [{ text:
    "You are extracting Texas economic-development announcements. From the markdown below, return ONLY data-center / AI / hyperscale / cloud-computing / server-farm projects. Ignore semiconductor fabs, pharma, manufacturing, shipbuilding, energy, and anything not a data center.\n\nReturn STRICT JSON: an array of objects with keys: company (string), county (string, the Texas county, no the word 'County'), investmentText (string, e.g. '$17 billion', or '' if none), projectType (string, short). Summarize in your OWN words — never copy sentences from the source. If no data centers are present, return [].\n\nMARKDOWN:\n" + $json.data.markdown
  }]}],
  generationConfig: { temperature: 0, responseMimeType: "application/json" }
}) }}

parameters.jsCode:
// Pull Gemini's JSON array out of the response, normalize, and emit a single
// item holding the candidate list. Defensive: tolerate code-fences / stray text.
const resp = $json;
let text = '';
try { text = resp.candidates[0].content.parts[0].text || ''; } catch (e) { text = ''; }
text = text.trim().replace(/^```(json)?/i, '').replace(/```$/,'').trim();
let arr = [];
try { arr = JSON.parse(text); } catch (e) {
  const m = text.match(/\[([\s\S]*)\]/);
  if (m) { try { arr = JSON.parse(m[0]); } catch (e2) { arr = []; } }
}
if (!Array.isArray(arr)) arr = [];
const candidates = arr
  .filter(c => c && c.company && c.county)
  .map(c => ({
    company: String(c.company).trim(),
    county: String(c.county).replace(/county/ig, '').trim(),
    investmentText: String(c.investmentText || '').trim(),
    projectType: String(c.projectType || 'data center').trim()
  }));
return [{ json: { candidates } }];

// Build one validated facility JSON per NEW, placeable data center.
const slugify = s => String(s).toLowerCase().normalize('NFKD').replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'');
const candidates = $('Parse candidates').first().json.candidates || [];
let _c = $('Get county centroids').first().json;
if (typeof _c === 'string') { try { _c = JSON.parse(_c); } catch (e) { _c = {}; } }
if (_c && typeof _c.data === 'string') { try { _c = JSON.parse(_c.data); } catch (e) {} }
const centroids = (_c && _c.counties) ? _c.counties : {};
const existingItems = $('Get existing facilities').all();
const existingSlugs = new Set(
  existingItems.flatMap(it => Array.isArray(it.json) ? it.json : [it.json])
    .map(f => (f && f.name ? String(f.name).replace(/\.json$/,'') : ''))
    .filter(Boolean)
);
const today = new Date().toISOString().slice(0,10);
const out = [];
for (const c of candidates) {
  const countyKey = c.county.toLowerCase().trim();
  const coords = centroids[countyKey];
  const slug = slugify(c.company + '-' + c.county + '-data-center');
  if (existingSlugs.has(slug)) continue;            // dedupe
  const noteInv = c.investmentText ? (' Announced ' + c.investmentText + '.') : '';
  const facility = {
    name: c.company + ' Data Center',
    operator: c.company,
    county: c.county,
    status: 'proposed',
    sourceUrl: 'https://gov.texas.gov/business/page/recent-project-announcements',
    sourceName: 'Office of the Governor — project announcements',
    note: ('Proposed ' + c.projectType + ' in ' + c.county + ' County.' + noteInv + ' (Our summary; see source.)').trim(),
    dateFound: today
  };
  if (coords && Number.isFinite(coords[0]) && Number.isFinite(coords[1])) {
    facility.lat = coords[0];
    facility.lng = coords[1];
    out.push({ json: { slug, placeable: true, facility } });
  } else {
    // County not in lookup: still surface it, but flag for manual coordinates.
    out.push({ json: { slug, placeable: false, missingCounty: c.county, facility } });
  }
}
return out;

